     1→/**
     2→ * Enhanced Website Uptime Monitor Widget
     3→ *
     4→ * Features:
     5→ * - Uptime history tracking with IndexedDB persistence
     6→ * - Uptime percentage display (24h, 7d, 30d)
     7→ * - Response time sparkline graph
     8→ * - Last checked timestamp
     9→ * - Auto-refresh every minute
    10→ */
    11→
    12→import React, { useState, useEffect, useCallback } from 'react';
    13→import { BaseWidget } from './BaseWidget';
    14→import {
    15→  useUptimeStore,
    16→  calculateUptimePercentage,
    17→  getAverageResponseTime,
    18→  getResponseTimeSparklineData,
    19→  formatRelativeTime,
    20→  type MonitoredSite,
    21→} from '../../stores/useUptimeStore';
    22→
    23→/**
    24→ * Mini Sparkline Component
    25→ * Simple SVG-based sparkline for response times
    26→ */
    27→const Sparkline: React.FC<{ data: number[]; width?: number; height?: number }> = ({
    28→  data,
    29→  width = 80,
    30→  height = 24,
    31→}) => {
    32→  if (data.length < 2) return null;
    33→
    34→  const max = Math.max(...data);
    35→  const min = Math.min(...data);
    36→  const range = max - min || 1;
    37→
    38→  const points = data.map((value, i) => {
    39→    const x = (i / (data.length - 1)) * width;
    40→    const y = height - ((value - min) / range) * (height - 4) - 2;
    41→    return `${x},${y}`;
    42→  });
    43→
    44→  const pathD = `M${points.join(' L')}`;
    45→
    46→  return (
    47→    <svg
    48→      width={width}
    49→      height={height}
    50→      className="inline-block"
    51→      viewBox={`0 0 ${width} ${height}`}
    52→    >
    53→      <path
    54→        d={pathD}
    55→        fill="none"
    56→        stroke="currentColor"
    57→        strokeWidth="1.5"
    58→        strokeLinecap="round"
    59→        strokeLinejoin="round"
    60→        className="text-accent-cyan"
    61→      />
    62→    </svg>
    63→  );
    64→};
    65→
    66→/**
    67→ * Uptime Badge Component
    68→ * Shows uptime percentage with color coding
    69→ */
    70→const UptimeBadge: React.FC<{ percentage: number | null; label: string }> = ({
    71→  percentage,
    72→  label,
    73→}) => {
    74→  const getColor = (pct: number | null) => {
    75→    if (pct === null) return 'bg-neutral-200 dark:bg-neutral-700 text-neutral-500';
    76→    if (pct >= 99) return 'bg-status-success/20 text-status-success';
    77→    if (pct >= 95) return 'bg-status-warning/20 text-status-warning';
    78→    return 'bg-status-error/20 text-status-error';
    79→  };
    80→
    81→  return (
    82→    <div
    83→      className={`px-2 py-0.5 rounded text-xs font-medium ${getColor(percentage)}`}
    84→      title={`${label} uptime`}
    85→    >
    86→      {percentage !== null ? `${percentage}%` : '–'}
    87→    </div>
    88→  );
    89→};
    90→
    91→/**
    92→ * Site Status Row Component
    93→ */
    94→const SiteStatusRow: React.FC<{
    95→  site: MonitoredSite;
    96→  onRemove: () => void;
    97→  expanded: boolean;
    98→  onToggleExpand: () => void;
    99→}> = ({ site, onRemove, expanded, onToggleExpand }) => {
   100→  const uptime24h = calculateUptimePercentage(site.checks, 24);
   101→  const uptime7d = calculateUptimePercentage(site.checks, 24 * 7);
   102→  const avgResponseTime = getAverageResponseTime(site.checks, 24);
   103→  const sparklineData = getResponseTimeSparklineData(site.checks, 20);
   104→
   105→  return (
   106→    <div className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg overflow-hidden transition-all duration-standard ease-smooth">
   107→      {/* Main Row */}
   108→      <div
   109→        className="flex items-center gap-3 p-3 cursor-pointer hover:bg-surface-light dark:hover:bg-neutral-800 transition-colors"
   110→        onClick={onToggleExpand}
   111→      >
   112→        {/* Status Indicator */}
   113→        <div className="relative flex-shrink-0">
   114→          <div
   115→            className={`w-3 h-3 rounded-full ${
   116→              site.isCurrentlyUp ? 'bg-status-success' : 'bg-status-error'
   117→            }`}
   118→          />
   119→          {site.isCurrentlyUp && (
   120→            <div className="absolute inset-0 w-3 h-3 rounded-full bg-status-success animate-ping opacity-50" />
   121→          )}
   122→        </div>
   123→
   124→        {/* Site Name & URL */}
   125→        <div className="flex-1 min-w-0">
   126→          <a
   127→            href={site.url}
   128→            target="_blank"
   129→            rel="noopener noreferrer"
   130→            onClick={(e) => e.stopPropagation()}
   131→            className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary hover:text-accent-cyan truncate block"
   132→          >
   133→            {site.name}
   134→          </a>
   135→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   136→            {formatRelativeTime(site.lastChecked)}
   137→          </div>
   138→        </div>
   139→
   140→        {/* Quick Uptime Badge */}
   141→        <UptimeBadge percentage={uptime24h} label="24h" />
   142→
   143→        {/* Expand Arrow */}
   144→        <span
   145→          className={`text-xs text-text-light-secondary dark:text-text-dark-secondary transition-transform ${
   146→            expanded ? 'rotate-180' : ''
   147→          }`}
   148→        >
   149→          ▼
   150→        </span>
   151→      </div>
   152→
   153→      {/* Expanded Details */}
   154→      {expanded && (
   155→        <div className="px-3 pb-3 pt-1 border-t border-border-light dark:border-border-dark space-y-3">
   156→          {/* Uptime Percentages */}
   157→          <div className="flex items-center gap-2">
   158→            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary w-14">
   159→              Uptime:
   160→            </span>
   161→            <div className="flex gap-2">
   162→              <div className="text-center">
   163→                <UptimeBadge percentage={uptime24h} label="24h" />
   164→                <div className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
   165→                  24h
   166→                </div>
   167→              </div>
   168→              <div className="text-center">
   169→                <UptimeBadge percentage={uptime7d} label="7d" />
   170→                <div className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
   171→                  7d
   172→                </div>
   173→              </div>
   174→            </div>
   175→          </div>
   176→
   177→          {/* Response Time */}
   178→          <div className="flex items-center gap-2">
   179→            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary w-14">
   180→              Avg RT:
   181→            </span>
   182→            <span className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary">
   183→              {avgResponseTime !== null ? `${avgResponseTime}ms` : '–'}
   184→            </span>
   185→            {sparklineData.length >= 2 && (
   186→              <div className="ml-auto">
   187→                <Sparkline data={sparklineData} />
   188→              </div>
   189→            )}
   190→          </div>
   191→
   192→          {/* Actions */}
   193→          <div className="flex justify-between items-center pt-2">
   194→            <span className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
   195→              {site.checks.length} checks recorded
   196→            </span>
   197→            <button
   198→              onClick={(e) => {
   199→                e.stopPropagation();
   200→                onRemove();
   201→              }}
   202→              className="text-xs text-status-error hover:underline"
   203→            >
   204→              Remove
   205→            </button>
   206→          </div>
   207→        </div>
   208→      )}
   209→    </div>
   210→  );
   211→};
   212→
   213→/**
   214→ * Main Uptime Widget Component
   215→ */
   216→export const UptimeWidget: React.FC = () => {
   217→  const { sites, addSite, removeSite, recordCheck } = useUptimeStore();
   218→  const [input, setInput] = useState('');
   219→  const [expandedSite, setExpandedSite] = useState<string | null>(null);
   220→  const [checking, setChecking] = useState(false);
   221→
   222→  /**
   223→   * Check site status with response time measurement
   224→   */
   225→  const checkSite = useCallback(async (url: string): Promise<{ isUp: boolean; responseTime: number | null }> => {
   226→    const startTime = performance.now();
   227→    try {
   228→      // Use no-cors mode since we can't read response headers from cross-origin
   229→      // The fetch will succeed if the server responds (even with errors)
   230→      await fetch(url, { method: 'HEAD', mode: 'no-cors' });
   231→      const responseTime = Math.round(performance.now() - startTime);
   232→      return { isUp: true, responseTime };
   233→    } catch {
   234→      return { isUp: false, responseTime: null };
   235→    }
   236→  }, []);
   237→
   238→  /**
   239→   * Check all sites
   240→   */
   241→  const checkAllSites = useCallback(async () => {
   242→    if (sites.length === 0) return;
   243→
   244→    setChecking(true);
   245→    for (const site of sites) {
   246→      const result = await checkSite(site.url);
   247→      recordCheck(site.url, result.isUp, result.responseTime);
   248→    }
   249→    setChecking(false);
   250→  }, [sites, checkSite, recordCheck]);
   251→
   252→  /**
   253→   * Add new site
   254→   */
   255→  const handleAddSite = () => {
   256→    if (input.trim()) {
   257→      addSite(input.trim());
   258→      setInput('');
   259→      // Check the new site immediately
   260→      setTimeout(checkAllSites, 100);
   261→    }
   262→  };
   263→
   264→  /**
   265→   * Auto-check sites on mount and every minute
   266→   */
   267→  useEffect(() => {
   268→    if (sites.length > 0) {
   269→      // Initial check
   270→      checkAllSites();
   271→
   272→      // Check every minute
   273→      const interval = setInterval(checkAllSites, 60000);
   274→      return () => clearInterval(interval);
   275→    }
   276→  }, [sites.length, checkAllSites]);
   277→
   278→  return (
   279→    <BaseWidget
   280→      title="Uptime Monitor"
   281→      icon="📡"
   282→      onRefresh={checkAllSites}
   283→      loading={checking}
   284→    >
   285→      <div className="space-y-3">
   286→        {/* Add Site Input */}
   287→        <div className="flex gap-2">
   288→          <input
   289→            type="url"
   290→            value={input}
   291→            onChange={(e) => setInput(e.target.value)}
   292→            onKeyPress={(e) => e.key === 'Enter' && handleAddSite()}
   293→            placeholder="Enter URL (e.g., google.com)"
   294→            className="flex-1 px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-cyan transition-all duration-standard ease-smooth"
   295→          />
   296→          <button
   297→            onClick={handleAddSite}
   298→            className="px-4 py-2 bg-accent-cyan hover:bg-accent-cyan-hover text-white rounded-button text-sm font-medium transition-all duration-standard ease-smooth"
   299→          >
   300→            Add
   301→          </button>
   302→        </div>
   303→
   304→        {/* Sites List */}
   305→        <div className="space-y-2 max-h-80 overflow-y-auto">
   306→          {sites.map((site) => (
   307→            <SiteStatusRow
   308→              key={site.url}
   309→              site={site}
   310→              onRemove={() => removeSite(site.url)}
   311→              expanded={expandedSite === site.url}
   312→              onToggleExpand={() =>
   313→                setExpandedSite(expandedSite === site.url ? null : site.url)
   314→              }
   315→            />
   316→          ))}
   317→        </div>
   318→
   319→        {/* Empty State */}
   320→        {sites.length === 0 && (
   321→          <div className="text-center py-6">
   322→            <div className="text-4xl mb-2">📡</div>
   323→            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   324→              Add websites to monitor their uptime
   325→            </p>
   326→            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   327→              Checks run every minute
   328→            </p>
   329→          </div>
   330→        )}
   331→
   332→        {/* Status Summary */}
   333→        {sites.length > 0 && (
   334→          <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary pt-2 border-t border-border-light dark:border-border-dark">
   335→            <span>
   336→              {sites.filter((s) => s.isCurrentlyUp).length}/{sites.length} online
   337→            </span>
   338→            <span>Checks every 1m</span>
   339→          </div>
   340→        )}
   341→      </div>
   342→    </BaseWidget>
   343→  );
   344→};
