 * Simple SVG-based sparkline for response times
 */
const Sparkline: React.FC<{ data: number[]; width?: number; height?: number }> = ({
  data,
  width = 80,
  height = 24,
}) => {
  if (data.length < 2) return null;

  const max = Math.max(...data);
  const min = Math.min(...data);
  const range = max - min || 1;

  const points = data.map((value, i) => {
    const x = (i / (data.length - 1)) * width;
    const y = height - ((value - min) / range) * (height - 4) - 2;
    return `${x},${y}`;
  });

  const pathD = `M${points.join(' L')}`;

  return (
    <svg
      width={width}
      height={height}
      className="inline-block"
      viewBox={`0 0 ${width} ${height}`}
    >
      <path
        d={pathD}
        fill="none"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
        className="text-accent-cyan"
      />
    </svg>
  );
};

/**
 * Uptime Badge Component
 * Shows uptime percentage with color coding
 */
const UptimeBadge: React.FC<{ percentage: number | null; label: string }> = ({
  percentage,
  label,
}) => {
  const getColor = (pct: number | null) => {
    if (pct === null) return 'bg-neutral-200 dark:bg-neutral-700 text-neutral-500';
    if (pct >= 99) return 'bg-status-success/20 text-status-success';
    if (pct >= 95) return 'bg-status-warning/20 text-status-warning';
    return 'bg-status-error/20 text-status-error';
  };

  return (
    <div
      className={`px-2 py-0.5 rounded text-xs font-medium ${getColor(percentage)}`}
      title={`${label} uptime`}
    >
      {percentage !== null ? `${percentage}%` : '–'}
    </div>
  );
};

/**
 * Site Status Row Component
 */
const SiteStatusRow: React.FC<{
  site: MonitoredSite;
  onRemove: () => void;
  expanded: boolean;
  onToggleExpand: () => void;
}> = ({ site, onRemove, expanded, onToggleExpand }) => {
  const uptime24h = calculateUptimePercentage(site.checks, 24);
  const uptime7d = calculateUptimePercentage(site.checks, 24 * 7);
  const avgResponseTime = getAverageResponseTime(site.checks, 24);
  const sparklineData = getResponseTimeSparklineData(site.checks, 20);

  return (
    <div className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg overflow-hidden transition-all duration-standard ease-smooth">
      {/* Main Row */}
      <div
        className="flex items-center gap-3 p-3 cursor-pointer hover:bg-surface-light dark:hover:bg-neutral-800 transition-colors"
        onClick={onToggleExpand}
      >
        {/* Status Indicator */}
        <div className="relative flex-shrink-0">
          <div
            className={`w-3 h-3 rounded-full ${
              site.isCurrentlyUp ? 'bg-status-success' : 'bg-status-error'
            }`}
          />
          {site.isCurrentlyUp && (
            <div className="absolute inset-0 w-3 h-3 rounded-full bg-status-success animate-ping opacity-50" />
          )}
        </div>

        {/* Site Name & URL */}
        <div className="flex-1 min-w-0">
          <a
            href={site.url}
            target="_blank"
            rel="noopener noreferrer"
            onClick={(e) => e.stopPropagation()}
            className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary hover:text-accent-cyan truncate block"
          >
            {site.name}
          </a>
          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
            {formatRelativeTime(site.lastChecked)}
          </div>
        </div>

        {/* Quick Uptime Badge */}
        <UptimeBadge percentage={uptime24h} label="24h" />

        {/* Expand Arrow */}
        <span
          className={`text-xs text-text-light-secondary dark:text-text-dark-secondary transition-transform ${
            expanded ? 'rotate-180' : ''
          }`}
        >
          ▼
        </span>
      </div>

      {/* Expanded Details */}
      {expanded && (
        <div className="px-3 pb-3 pt-1 border-t border-border-light dark:border-border-dark space-y-3">
          {/* Uptime Percentages */}
          <div className="flex items-center gap-2">
            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary w-14">
              Uptime:
            </span>
            <div className="flex gap-2">
              <div className="text-center">
                <UptimeBadge percentage={uptime24h} label="24h" />
                <div className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
                  24h
                </div>
              </div>
              <div className="text-center">
                <UptimeBadge percentage={uptime7d} label="7d" />
                <div className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
                  7d
                </div>
              </div>
            </div>
          </div>

          {/* Response Time */}
          <div className="flex items-center gap-2">
            <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary w-14">
              Avg RT:
            </span>
            <span className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary">
              {avgResponseTime !== null ? `${avgResponseTime}ms` : '–'}
            </span>
            {sparklineData.length >= 2 && (
              <div className="ml-auto">
                <Sparkline data={sparklineData} />
              </div>
            )}
          </div>

          {/* Actions */}
          <div className="flex justify-between items-center pt-2">
            <span className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
              {site.checks.length} checks recorded
            </span>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onRemove();
              }}
              className="text-xs text-status-error hover:underline"
            >
              Remove
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

/**
 * Main Uptime Widget Component
 */
export const UptimeWidget: React.FC = () => {
  const { sites, addSite, removeSite, recordCheck } = useUptimeStore();
  const [input, setInput] = useState('');
  const [expandedSite, setExpandedSite] = useState<string | null>(null);
  const [checking, setChecking] = useState(false);

  /**
   * Check site status with response time measurement
   */
  const checkSite = useCallback(async (url: string): Promise<{ isUp: boolean; responseTime: number | null }> => {
    const startTime = performance.now();
    try {
      // Use no-cors mode since we can't read response headers from cross-origin
      // The fetch will succeed if the server responds (even with errors)
      await fetch(url, { method: 'HEAD', mode: 'no-cors' });
      const responseTime = Math.round(performance.now() - startTime);
      return { isUp: true, responseTime };
    } catch {
      return { isUp: false, responseTime: null };
    }
  }, []);

  /**
   * Check all sites
   */
  const checkAllSites = useCallback(async () => {
    if (sites.length === 0) return;

    setChecking(true);
    for (const site of sites) {
      const result = await checkSite(site.url);
      recordCheck(site.url, result.isUp, result.responseTime);
    }
    setChecking(false);
  }, [sites, checkSite, recordCheck]);

  /**
   * Add new site
   */
  const handleAddSite = () => {
    if (input.trim()) {
      addSite(input.trim());
      setInput('');
      // Check the new site immediately
      setTimeout(checkAllSites, 100);
    }
  };

  /**
   * Auto-check sites on mount and every minute
   */
  useEffect(() => {
    if (sites.length > 0) {
      // Initial check
      checkAllSites();

      // Check every minute
      const interval = setInterval(checkAllSites, 60000);
      return () => clearInterval(interval);
    }
  }, [sites.length, checkAllSites]);

  return (
    <BaseWidget
      title="Uptime Monitor"
      icon="📡"
      onRefresh={checkAllSites}
      loading={checking}
    >
      <div className="space-y-3">
        {/* Add Site Input */}
        <div className="flex gap-2">
          <input
            type="url"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleAddSite()}
            placeholder="Enter URL (e.g., google.com)"
            className="flex-1 px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-cyan transition-all duration-standard ease-smooth"
          />
          <button
            onClick={handleAddSite}
            className="px-4 py-2 bg-accent-cyan hover:bg-accent-cyan-hover text-white rounded-button text-sm font-medium transition-all duration-standard ease-smooth"
          >
            Add
          </button>
        </div>

        {/* Sites List */}
        <div className="space-y-2 max-h-80 overflow-y-auto">
          {sites.map((site) => (
            <SiteStatusRow
              key={site.url}
              site={site}
              onRemove={() => removeSite(site.url)}
              expanded={expandedSite === site.url}
              onToggleExpand={() =>
                setExpandedSite(expandedSite === site.url ? null : site.url)
              }
            />
          ))}
        </div>

        {/* Empty State */}
        {sites.length === 0 && (
          <div className="text-center py-6">
            <div className="text-4xl mb-2">📡</div>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Add websites to monitor their uptime
            </p>
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
              Checks run every minute
            </p>
          </div>
        )}

        {/* Status Summary */}
        {sites.length > 0 && (
          <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary pt-2 border-t border-border-light dark:border-border-dark">
            <span>
              {sites.filter((s) => s.isCurrentlyUp).length}/{sites.length} online
            </span>
            <span>Checks every 1m</span>
          </div>
        )}
      </div>
    </BaseWidget>
  );
};

/**
 * Shortcuts Reference Widget
 * Quick reference for Neuman Brain keyboard shortcuts
 */

import React, { useState } from 'react';
import { BaseWidget } from './BaseWidget';

const shortcuts = [
  { category: 'Navigation', items: [
    { keys: '⌘ D', action: 'Dashboard' },
    { keys: '⌘ N', action: 'Notes' },
    { keys: '⌘ P', action: 'Planning' },
    { keys: '⌘ T', action: 'Tasks' },
    { keys: '⌘ S', action: 'Settings' },
  ]},
  { category: 'General', items: [
    { keys: '⌘ B', action: 'Toggle Sidebar' },
    { keys: '⌘ K', action: 'Quick Search' },
    { keys: 'Esc', action: 'Close Modal' },
  ]},
];

export const ShortcutsWidget: React.FC = () => {
  const [search, setSearch] = useState('');

  const filtered = shortcuts.map(cat => ({
    ...cat,
    items: cat.items.filter(item =>
      item.action.toLowerCase().includes(search.toLowerCase()) ||
      item.keys.toLowerCase().includes(search.toLowerCase())
    ),
  })).filter(cat => cat.items.length > 0);

  return (
    <BaseWidget title="Keyboard Shortcuts" icon="⌨️">
      <div className="space-y-3">
        <input
          type="text"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search shortcuts..."
          className="w-full px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue transition-all duration-standard ease-smooth"
        />

        <div className="space-y-2 max-h-64 overflow-y-auto">
          {filtered.map((cat) => (
            <div key={cat.category}>
              <h4 className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-1">
                {cat.category}
              </h4>
              {cat.items.map((item, idx) => (
                <div key={idx} className="flex justify-between items-center py-1.5 px-2 hover:bg-neutral-100 dark:hover:bg-neutral-800 rounded-button transition-all duration-standard ease-smooth">
                  <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
                    {item.action}
                  </span>
                  <kbd className="px-2 py-0.5 text-xs font-mono bg-neutral-200 dark:bg-neutral-700 rounded-button transition-all duration-standard ease-smooth">
                    {item.keys}
                  </kbd>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    </BaseWidget>
  );
};

