import React, { useState, useEffect, useCallback } from 'react';
import { BaseWidget } from './BaseWidget';
import {
  useUptimeStore,
  calculateUptimePercentage,
  getAverageResponseTime,
  getResponseTimeSparklineData,
  formatRelativeTime,
