      const interval = setInterval(checkAllSites, 60000);
      return () => clearInterval(interval);
    }
  }, [sites.length, checkAllSites]);

  return (
    <BaseWidget
      title="Uptime Monitor"
      icon="📡"
      onRefresh={checkAllSites}
      loading={checking}
    >
      <div className="space-y-3">
        {/* Add Site Input */}
        <div className="flex gap-2">
          <input
            type="url"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleAddSite()}
            placeholder="Enter URL (e.g., google.com)"
            className="flex-1 px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-cyan transition-all duration-standard ease-smooth"
          />
          <button
            onClick={handleAddSite}
            className="px-4 py-2 bg-accent-cyan hover:bg-accent-cyan-hover text-white rounded-button text-sm font-medium transition-all duration-standard ease-smooth"
          >
            Add
          </button>
        </div>

        {/* Sites List */}
        <div className="space-y-2 max-h-80 overflow-y-auto">
          {sites.map((site) => (
            <SiteStatusRow
              key={site.url}
              site={site}
              onRemove={() => removeSite(site.url)}
              expanded={expandedSite === site.url}
              onToggleExpand={() =>
                setExpandedSite(expandedSite === site.url ? null : site.url)
              }
            />
          ))}
        </div>

        {/* Empty State */}
        {sites.length === 0 && (
          <div className="text-center py-6">
            <div className="text-4xl mb-2">📡</div>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Add websites to monitor their uptime
            </p>
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
              Checks run every minute
            </p>
          </div>
        )}

        {/* Status Summary */}
        {sites.length > 0 && (
          <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary pt-2 border-t border-border-light dark:border-border-dark">
            <span>
              {sites.filter((s) => s.isCurrentlyUp).length}/{sites.length} online
            </span>
            <span>Checks every 1m</span>
          </div>
        )}
      </div>
    </BaseWidget>
  );
};

