/**
 * Shortcuts Reference Widget
 * Quick reference for Neuman Brain keyboard shortcuts
 */

import React, { useState } from 'react';
import { BaseWidget } from './BaseWidget';

const shortcuts = [
  { category: 'Navigation', items: [
    { keys: '⌘ D', action: 'Dashboard' },
    { keys: '⌘ N', action: 'Notes' },
    { keys: '⌘ P', action: 'Planning' },
    { keys: '⌘ T', action: 'Tasks' },
    { keys: '⌘ S', action: 'Settings' },
  ]},
  { category: 'General', items: [
    { keys: '⌘ B', action: 'Toggle Sidebar' },
    { keys: '⌘ K', action: 'Quick Search' },
    { keys: 'Esc', action: 'Close Modal' },
  ]},
];

export const ShortcutsWidget: React.FC = () => {
  const [search, setSearch] = useState('');

  const filtered = shortcuts.map(cat => ({
    ...cat,
    items: cat.items.filter(item =>
      item.action.toLowerCase().includes(search.toLowerCase()) ||
      item.keys.toLowerCase().includes(search.toLowerCase())
    ),
  })).filter(cat => cat.items.length > 0);

  return (
    <BaseWidget title="Keyboard Shortcuts" icon="⌨️">
      <div className="space-y-3">
        <input
          type="text"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search shortcuts..."
          className="w-full px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue transition-all duration-standard ease-smooth"
        />

        <div className="space-y-2 max-h-64 overflow-y-auto">
          {filtered.map((cat) => (
            <div key={cat.category}>
              <h4 className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-1">
                {cat.category}
              </h4>
              {cat.items.map((item, idx) => (
                <div key={idx} className="flex justify-between items-center py-1.5 px-2 hover:bg-neutral-100 dark:hover:bg-neutral-800 rounded-button transition-all duration-standard ease-smooth">
                  <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
                    {item.action}
                  </span>
                  <kbd className="px-2 py-0.5 text-xs font-mono bg-neutral-200 dark:bg-neutral-700 rounded-button transition-all duration-standard ease-smooth">
                    {item.keys}
                  </kbd>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    </BaseWidget>
  );
};

/**
 * Pomodoro Timer Widget
 *
 * 25-minute focus timer for productivity (local, no API)
 */

import React, { useState, useEffect } from 'react';
import { BaseWidget } from './BaseWidget';
import { useWidgetStore } from '../../stores/useWidgetStore';

export const PomodoroWidget: React.FC = () => {
  const settings = useWidgetStore((state) => state.getWidgetSettings('pomodoro'));
  const [timeLeft, setTimeLeft] = useState(settings.duration * 60 || 25 * 60); // seconds
  const [isRunning, setIsRunning] = useState(false);

  useEffect(() => {
    if (!isRunning) return;

    const interval = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1) {
          setIsRunning(false);
          // Notification
          if ('Notification' in window && Notification.permission === 'granted') {
            new Notification('Pomodoro Complete!', {
              body: 'Time for a break!',
            });
          }
          return settings.duration * 60 || 25 * 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, [isRunning, settings.duration]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleStart = () => setIsRunning(true);
  const handlePause = () => setIsRunning(false);
  const handleReset = () => {
    setIsRunning(false);
    setTimeLeft(settings.duration * 60 || 25 * 60);
  };

  const progress = ((timeLeft / ((settings.duration || 25) * 60)) * 100);

  return (
    <BaseWidget title="Pomodoro Timer" icon="⏱️">
      <div className="flex flex-col items-center justify-center h-full gap-4">
        {/* Timer Display */}
        <div className="relative w-32 h-32">
          <svg className="w-full h-full -rotate-90">
            <circle
              cx="64"
              cy="64"
              r="60"
              fill="none"
              stroke="currentColor"
              strokeWidth="8"
              className="text-neutral-200 dark:text-neutral-700"
            />
            <circle
              cx="64"
              cy="64"
              r="60"
              fill="none"
              stroke="currentColor"
              strokeWidth="8"
              strokeDasharray={377}
              strokeDashoffset={377 - (377 * progress) / 100}
              className="text-accent-blue transition-all"
            />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-3xl font-bold text-text-light-primary dark:text-text-dark-primary">
              {formatTime(timeLeft)}
            </span>
          </div>
        </div>

        {/* Controls */}
        <div className="flex gap-2">
          {!isRunning ? (
            <button
              onClick={handleStart}
              className="px-4 py-2 bg-accent-blue text-white rounded-button hover:bg-accent-blue-hover transition-all duration-standard ease-smooth"
            >
              Start
            </button>
          ) : (
            <button
              onClick={handlePause}
              className="px-4 py-2 bg-status-warning text-white rounded-button hover:opacity-80 transition-all duration-standard ease-smooth"
            >
              Pause
            </button>
          )}
          <button
            onClick={handleReset}
            className="px-4 py-2 bg-neutral-600 text-white rounded-button hover:opacity-80 transition-all duration-standard ease-smooth"
          >
            Reset
          </button>
        </div>
      </div>
    </BaseWidget>
  );
};

